SELECT firtMst.plan_nm as firstPlanNm , mst.root_plan_id , mst.plan_id , mst.plan_nm , parPlan.childCount , swMapCnt.swCnt , mst.modl_cd , smdl.model_name as modlNm , mst.stb_cmcl_fg_cd , mst.stb_sw_plan_last_ver , mst.stb_ui_ver , usm.upd_scop_cd , cd5.cd_nm as updScopNm , cd1.cd_nm as stbCmclFgNm , cd3.cd_nm as planAplFgNm , cd3.COMM_CD as planAplFgCd , mst.upd_sts_fg_cd , cd4.cd_nm as updStsFgNm , usr.user_nm as regNm , to_char(mst.stm_fir_reg_date,'yyyy.mm.dd') stm_fir_reg_date , to_char(mst.stm_last_upd_date,'yyyy.mm.dd') stm_last_upd_date , mst.stm_fir_reg_date FROM um_upd_plan_mst mst , um_upd_plan_mst firtMst , um_upd_plan_sw_map uupsm , um_sw_mst usm , stb_model smdl , ad_user_mst usr , ad_comm_cd cd1 , ad_comm_cd cd3 , ad_comm_cd cd4 , ad_comm_cd cd5 ,(select count(*) as childCount ,par_plan_id from um_upd_plan_mst where par_plan_id is not null AND PAR_PLAN_ID != PLAN_ID group by par_plan_id) parPlan ,(SELECT plan_id, count(*) as swCnt FROM um_upd_plan_sw_map GROUP BY PLAN_ID) swMapCnt WHERE 1=1 AND mst.root_plan_id = firtMst.plan_id(+) AND mst.plan_id = uupsm.plan_id(+) AND mst.plan_id = parPlan.par_plan_id(+) AND mst.plan_id = swMapCnt.plan_id(+) AND mst.STB_SW_PLAN_LAST_VER = uupsm.STB_SW_VER(+) AND uupsm.sw_id = usm.sw_id(+) AND usr.user_id(+) = mst.stm_fir_reg_user_id AND mst.modl_cd = smdl.model_code AND cd1.comm_grp_cd = 'STB_CMCL_FG_CD' AND cd1.comm_cd = mst.stb_cmcl_fg_cd AND cd3.comm_grp_cd = 'PLAN_APL_FG_CD' AND cd3.comm_cd = mst.plan_apl_fg_cd AND cd4.comm_grp_cd(+) = 'UPD_STS_FG_CD' AND cd4.comm_cd(+)= mst.upd_sts_fg_cd AND cd5.comm_grp_cd(+) = 'UPD_SCOP_CD' AND cd5.comm_cd(+) = usm.upd_scop_cd
AND mst.plan_apl_fg_cd in ('01','02','03')
AND mst.plan_apl_fg_cd = '04'
AND UPPER(firtMst.plan_nm) like '%' || UPPER(#{firstPlanNm}) || '%'
AND UPPER(mst.plan_nm) like '%' || UPPER(#{planNm}) || '%'
AND mst.modl_cd IN
#{value}
AND mst.plan_apl_fg_cd IN
#{value}
AND mst.stb_cmcl_fg_cd IN
#{value}
AND mst.upd_sts_fg_cd IN
#{value}
AND usm.upd_scop_cd = #{updScopCd}
AND usr.user_id IN
#{value}
AND mst.stm_fir_reg_date between to_date(#{fromDt}||'00:00:00','yyyyMMdd HH24:MI:SS') and to_date(#{toDt}||'23:59:59','yyyyMMdd HH24:MI:SS')
AND to_char(mst.stm_fir_reg_date,'yyyyMMdd') = #{fromDt}
AND mst.stm_fir_reg_date >= to_date(#{fromDt})
AND mst.stm_fir_reg_date <= to_date(#{fromDt})
AND REPLACE(mst.stb_ui_ver,'.','') between #{uiFromVersion} and #{uiToVersion}
AND REPLACE(mst.stb_ui_ver,'.','') = #{uiFromVersion}
AND REPLACE(mst.stb_ui_ver,'.','') >= #{uiFromVersion}
AND REPLACE(mst.stb_ui_ver,'.','') <= #{uiFromVersion}
AND REPLACE(mst.stb_sw_plan_last_ver,'.','') between #{swFromVersion} and #{swToVersion}
AND REPLACE(mst.stb_sw_plan_last_ver,'.','') = #{swFromVersion}
AND REPLACE(mst.stb_sw_plan_last_ver,'.','') >= #{swFromVersion}
AND REPLACE(mst.stb_sw_plan_last_ver,'.','') <= #{swFromVersion}
ORDER BY mst.stm_last_upd_date DESC

SELECT firtMst.plan_nm as firstPlanNm , mst.root_plan_id , mst.plan_id , mst.plan_nm , parPlan.childCount , NVL2(apmap.ref_plan_id, apswMapCnt.swCnt, swMapCnt.swCnt) as swCnt , mst.modl_cd , smdl.model_name as modlNm , mst.stb_cmcl_fg_cd , mst.stb_sw_plan_last_ver , mst.stb_ui_ver , NVL2(apmap.ref_plan_id, apswmst.upd_scop_cd, usm.upd_scop_cd) upd_scop_cd , NVL2(apmap.ref_plan_id, apcommcd.cd_nm, cd5.cd_nm) as updScopNm , cd1.cd_nm as stbCmclFgNm , cd3.cd_nm as planAplFgNm , cd3.COMM_CD as planAplFgCd , mst.upd_sts_fg_cd , CASE WHEN mst.upd_sts_fg_cd = '2' AND SCH_LST.PLAN_CNT > 0 AND SCH_LST.GOING_CNT = 0 THEN '진행예정' -- 계획서가 진행(2) 일 때, 계획 중인 수행계획이 있으면 "진행예정" 으로 표기 ELSE cd4.cd_nm END as updStsFgNm , usr.user_nm as regNm , to_char(mst.stm_fir_reg_date,'yyyy.mm.dd') stm_fir_reg_date , to_char(mst.stm_last_upd_date,'yyyy.mm.dd') stm_last_upd_date , mst.stm_fir_reg_date , mst.scrbr_typ_cd , (SELECT COMM.CD_NM FROM AD_COMM_CD COMM WHERE COMM.COMM_GRP_CD = 'SCRBR_TYP_CD' AND COMM.COMM_CD = mst.SCRBR_TYP_CD ) SCRBR_TYP_NM FROM um_upd_plan_mst mst , um_upd_plan_mst firtMst , um_upd_plan_sw_map uupsm , um_sw_mst usm , stb_model smdl , ad_user_mst usr , ad_comm_cd cd1 , ad_comm_cd cd3 , ad_comm_cd cd4 , ad_comm_cd cd5 ,(select count(*) as childCount ,par_plan_id from um_upd_plan_mst where par_plan_id is not null AND PAR_PLAN_ID != PLAN_ID group by par_plan_id) parPlan ,(SELECT plan_id, count(*) as swCnt FROM um_upd_plan_sw_map GROUP BY PLAN_ID) swMapCnt ------------ join for ref_plan_id ----------- , um_auth_plan_map apmap , um_upd_plan_mst apmst , um_upd_plan_sw_map apswmap , um_sw_mst apswmst , (select plan_id, count(*) as swCnt from um_upd_plan_sw_map group by plan_id) apswMapCnt , ad_comm_cd apcommcd , (SELECT PLAN_ID , SUM(DECODE(UPD_STS_FG_CD, 1, 1, 0)) PLAN_CNT , SUM(DECODE(UPD_STS_FG_CD, 2, 1, 0)) GOING_CNT , SUM(DECODE(UPD_STS_FG_CD, 3, 1, 0)) COMPLETE_CNT , SUM(DECODE(UPD_STS_FG_CD, 4, 1, 0)) STOP_CNT FROM UM_UPD_PLAN_EXE_SCH_LST GROUP BY PLAN_ID ) SCH_LST WHERE 1=1 AND mst.root_plan_id = firtMst.plan_id(+) AND mst.plan_id = uupsm.plan_id(+) AND mst.plan_id = parPlan.par_plan_id(+) AND mst.plan_id = swMapCnt.plan_id(+) AND mst.STB_SW_PLAN_LAST_VER = uupsm.STB_SW_VER(+) AND uupsm.sw_id = usm.sw_id(+) AND usr.user_id(+) = mst.stm_fir_reg_user_id AND mst.modl_cd = smdl.model_code AND cd1.comm_grp_cd = 'STB_CMCL_FG_CD' AND cd1.comm_cd = mst.stb_cmcl_fg_cd AND cd3.comm_grp_cd = 'PLAN_APL_FG_CD' AND cd3.comm_cd = mst.plan_apl_fg_cd AND cd4.comm_grp_cd(+) = 'UPD_STS_FG_CD' AND cd4.comm_cd(+)= mst.upd_sts_fg_cd AND cd5.comm_grp_cd(+) = 'UPD_SCOP_CD' AND cd5.comm_cd(+) = usm.upd_scop_cd --------------- join for ref_plan_id ----------- AND mst.plan_id = apmap.auth_plan_id(+) AND mst.root_plan_id = apmap.root_plan_id(+) AND apmap.ref_plan_id = apmst.plan_id(+) AND apmst.plan_id = apswmap.plan_id(+) AND apmst.stb_sw_plan_last_ver = apswmap.stb_sw_ver(+) AND apswmap.sw_id = apswmst.sw_id(+) AND apmst.plan_id = apswMapCnt.plan_id(+) AND apcommcd.comm_grp_cd(+) = 'UPD_SCOP_CD' AND apcommcd.comm_cd(+) = apswmst.upd_scop_cd AND SCH_LST.PLAN_ID(+) = MST.PLAN_ID
AND mst.plan_apl_fg_cd in ('01','02','03')
AND mst.plan_apl_fg_cd = '04'
AND UPPER(firtMst.plan_nm) like '%' || UPPER(#{firstPlanNm}) || '%'
AND UPPER(mst.plan_nm) like '%' || UPPER(#{planNm}) || '%'
AND mst.modl_cd IN
#{value}
AND mst.plan_apl_fg_cd IN
#{value}
AND mst.stb_cmcl_fg_cd IN
#{value}
AND mst.upd_sts_fg_cd IN
#{value}
AND usm.upd_scop_cd = #{updScopCd}
AND usr.user_id IN
#{value}
AND mst.stm_fir_reg_date between to_date(#{fromDt}||'00:00:00','yyyyMMdd HH24:MI:SS') and to_date(#{toDt}||'23:59:59','yyyyMMdd HH24:MI:SS')
AND to_char(mst.stm_fir_reg_date,'yyyyMMdd') = #{fromDt}
AND mst.stm_fir_reg_date >= to_date(#{fromDt})
AND mst.stm_fir_reg_date <= to_date(#{fromDt})
AND REPLACE(mst.stb_ui_ver,'.','') between #{uiFromVersion} and #{uiToVersion}
AND REPLACE(mst.stb_ui_ver,'.','') = #{uiFromVersion}
AND REPLACE(mst.stb_ui_ver,'.','') >= #{uiFromVersion}
AND REPLACE(mst.stb_ui_ver,'.','') <= #{uiFromVersion}
AND REPLACE(mst.stb_sw_plan_last_ver,'.','') between #{swFromVersion} and #{swToVersion}
AND REPLACE(mst.stb_sw_plan_last_ver,'.','') = #{swFromVersion}
AND REPLACE(mst.stb_sw_plan_last_ver,'.','') >= #{swFromVersion}
AND REPLACE(mst.stb_sw_plan_last_ver,'.','') <= #{swFromVersion}
ORDER BY mst.stm_last_upd_date DESC

	SELECT uupsm.stb_id
	FROM  um_upd_plan_stb_map uupsm
