SELECT dmst.dvc_grp_id ,dmst.dvc_grp_nm ,dmst.dvc_grp_fg_cd ,cd.cd_nm as dvc_grp_fg_nm ,CASE WHEN dmst.dvc_grp_fg_cd = '01' THEN '0' ELSE TO_CHAR(dmst.grp_tgt_qty) END grpTgtQty ,dmst.use_yn ,dmst.dvc_grp_expl ,dmst.grp_tgt_cond_cts ,(select user_nm from ad_user_mst where user_id = dmst.stm_fir_reg_user_id) as regNm , to_char(dmst.stm_fir_reg_date,'yyyy.mm.dd hh24:mi') stm_fir_reg_date ,(select user_nm from ad_user_mst where user_id = dmst.stm_last_upd_user_id) as updNm ,to_char(dmst.stm_last_upd_date,'yyyy.mm.dd hh24:mi') stm_last_upd_date
, CASE WHEN dmst.dvc_grp_id in ( SELECT dvc_grp_id FROM um_upd_plan_dvc_grp_map WHERE plan_id = #{planId} AND ecpt_tgt_yn = #{ecptTgtYn} ) THEN 'Y' ELSE 'N' END myDvcGrpYn
,'N' AS myDvcGrpYn
FROM dm_dvc_grp_mst dmst ,ad_comm_cd cd WHERE 1=1 AND dmst.DEL_YN = 'N' AND dmst.USE_YN = 'Y' AND cd.comm_grp_cd = 'DVC_GRP_FG_CD' AND dmst.dvc_grp_fg_cd = cd.comm_cd
AND dmst.dvc_grp_nm LIKE '%' || #{dvcGrpNm} || '%'
AND dmst.dvc_grp_fg_cd = #{dvcGrpFgCd}
AND dmst.use_yn = #{useYn}
AND dmst.stm_fir_reg_user_id IN
#{value}
ORDER BY dmst.stm_last_upd_date desc

       SELECT map.stb_id
