SELECT /*+ PARALLEL(4) */ DDM.STB_ID ,DECODE(LENGTH(STB.USER_SERVICE_NUM),10,'상용','테스트용' ) STBDIVISION ,PS.MAC_ADDRESS ,(SELECT SM.MODEL_NAME FROM STB_MODEL SM WHERE SM.MODEL_CODE = PS.MODEL_CODE AND ROWNUM = 1) MODEL_NAME ,(SELECT MCM.CUG_NM FROM DM_CUG_MST DCM ,MN_CUG_MST MCM WHERE STB.SERVICE_CODE = DCM.CUG_ID AND DCM.CUG_ID = MCM.CUG_ID AND ROWNUM = 1) CUG_EXPL ,(SELECT COMM.CD_NM FROM AD_COMM_CD COMM WHERE COMM.COMM_GRP_CD = 'IPTV_STATUS_CODE' AND COMM.COMM_CD = STB.IPTV_STATUS_CODE AND ROWNUM = 1) CD_NM ,DDPM.CLNT_IPADDR ,DDM.STB_SW_VER STB_SW_PLAN_INST_VER ,DDM.STB_SW_PLAN_LAST_VER ,TO_CHAR(DDPM.STM_UPTM, 'YYYY.MM.DD HH24:MI') STM_UPTM ,DECODE(DDPM.STM_UPTM,NULL,'',TRUNC(SYSDATE) - TRUNC(DDPM.STM_UPTM)||'일') AS OVERUPTIME ,'N' AS MYSTBYN ,(SELECT DQTM.TEAM_NM FROM DM_QLTY_TEAM_MST DQTM WHERE DDM.TEAM_CD = DQTM.TEAM_CD AND ROWNUM = 1) AREAQLTY ,STB.USER_SERVICE_NUM ,DECODE(DDPM.HDMI_POW,'1','사용함','0','사용 안함',NULL) HDMI_POW ,DECODE(DDPM.RCU_PAIRING,'true','Y','false','N',NULL) RCU_PAIRING ,DDM.TEAM_CD FROM STB STB ,DM_DVC_MST DDM ,PHYSICAL_STB PS ,DM_DVC_PRVN_MST DDPM
,DM_DVC_GRP_MST GM ,DM_DVC_GRP_PSNL_MAP GPM
WHERE 1=1 AND DDM.STB_ID = STB.STB_ID AND DDM.STB_ID = PS.STB_ID (+) AND DDM.STB_ID = DDPM.STB_ID (+)
AND GM.DVC_GRP_ID = GPM.DVC_GRP_ID(+) AND DDM.STB_ID = GPM.STB_ID AND GM.DVC_GRP_FG_CD = '02' AND UPPER(GM.DVC_GRP_NM) LIKE UPPER('%' || #{deviceGroup} || '%')
AND UPPER(PS.MAC_ADDRESS) = UPPER(#{macAddress})
AND ${otherCondition} = #{otherTxt}
AND STB.STB_ID = UPPER(#{stbId})
AND REPLACE(${versionCondition},'.','') BETWEEN #{toVersion} AND #{fromVersion}
AND REPLACE(${versionCondition},'.','') = #{toVersion}
AND REPLACE(${versionCondition},'.','') >= #{toVersion}
AND REPLACE(${versionCondition},'.','') <= #{toVersion}
AND DDM.TEAM_CD IN
