#{type}
AND STB.IPTV_STATUS_CODE IN
#{type}
AND STB.ID_PACKAGE IN
#{type}
AND DDPM.STM_UPTM BETWEEN TO_DATE(#{fromUptm}||'00:00:00','yyyyMMdd HH24:MI:SS') AND TO_DATE(#{toUptm}||'23:59:59','yyyyMMdd HH24:MI:SS')
AND DDPM.STM_UPTM BETWEEN TO_DATE(#{fromUptm}||'00:00:00','yyyyMMdd HH24:MI:SS') AND TO_DATE(#{fromUptm}||'23:59:59','yyyyMMdd HH24:MI:SS')
AND DDPM.STM_UPTM >= TO_DATE(#{fromUptm})
AND DDPM.STM_UPTM <= TO_DATE(#{fromUptm})
AND TRUNC(SYSDATE) - TRUNC(DDPM.STM_UPTM) BETWEEN #{overTimeFrom} and #{overTimeTo}
AND TRUNC(SYSDATE) - TRUNC(DDPM.STM_UPTM) = #{overTime}
AND TRUNC(SYSDATE) - TRUNC(DDPM.STM_UPTM) >= #{overTime}
AND TRUNC(SYSDATE) - TRUNC(DDPM.STM_UPTM) <= #{overTime}
AND LENGTH(STB.USER_SERVICE_NUM) = 10
AND LENGTH(STB.USER_SERVICE_NUM) != 10
AND ddm.stb_id not in ( SELECT stb_id FROM um_upd_plan_stb_map WHERE plan_id = #{planId} AND ecpt_tgt_yn = #{ecptTgtYn})
AND ddm.stb_id in ( SELECT stb_id FROM um_upd_plan_stb_map WHERE plan_id = #{planId} AND ecpt_tgt_yn = #{ecptTgtYn})
ORDER BY DDM.STB_ID

