		AND PLAN_ID != #{value}

SELECT firstMst.plan_nm as firstPlanNm , mst.root_plan_id , mst.plan_id , mst.plan_nm , (SELECT COUNT(*) FROM um_upd_plan_mst child WHERE child.par_plan_id = mst.plan_id AND child.par_plan_id != child.plan_id ) AS childCount , NVL2(apmap.ref_plan_id, apswMapCnt.swCnt, swMapCnt.swCnt) as swCnt , mst.modl_cd , smdl.model_name as modlNm , mst.stb_cmcl_fg_cd , mst.stb_sw_plan_last_ver , mst.stb_ui_ver , NVL2(apmap.ref_plan_id, apswmst.upd_scop_cd, usm.upd_scop_cd) upd_scop_cd , NVL2(apmap.ref_plan_id, apcommcd.cd_nm, cd5.cd_nm) as updScopNm , cd1.cd_nm as stbCmclFgNm , cd3.cd_nm as planAplFgNm , cd3.COMM_CD as planAplFgCd , mst.upd_sts_fg_cd , cd4.cd_nm as updStsFgNm , usr.user_nm as regNm , to_char(mst.stm_fir_reg_date,'yyyy.mm.dd') stm_fir_reg_date , to_char(mst.stm_last_upd_date,'yyyy.mm.dd') stm_last_upd_date , mst.scrbr_typ_cd , (SELECT COMM.CD_NM FROM AD_COMM_CD COMM WHERE COMM.COMM_GRP_CD = 'SCRBR_TYP_CD' AND COMM.COMM_CD = mst.SCRBR_TYP_CD ) SCRBR_TYP_NM FROM um_upd_plan_mst mst , um_upd_plan_mst firstMst , um_upd_plan_sw_map uupsm , um_sw_mst usm , stb_model smdl , ad_user_mst usr , ad_comm_cd cd1 , ad_comm_cd cd3 , ad_comm_cd cd4 , ad_comm_cd cd5 , (SELECT plan_id, count(*) as swCnt FROM um_upd_plan_sw_map GROUP BY plan_id) swMapCnt , um_auth_plan_map apmap , um_upd_plan_mst apmst , um_upd_plan_sw_map apswmap , um_sw_mst apswmst , (select plan_id, count(*) as swCnt from um_upd_plan_sw_map group by plan_id) apswMapCnt , ad_comm_cd apcommcd WHERE mst.root_plan_id = firstMst.plan_id(+) AND mst.plan_id = uupsm.plan_id(+) AND mst.plan_id = swMapCnt.plan_id(+) AND mst.STB_SW_PLAN_LAST_VER = uupsm.STB_SW_VER(+) AND uupsm.sw_id = usm.sw_id(+) AND usr.user_id(+) = mst.stm_fir_reg_user_id AND mst.modl_cd = smdl.model_code AND cd1.comm_grp_cd = 'STB_CMCL_FG_CD' AND cd1.comm_cd = mst.stb_cmcl_fg_cd AND cd3.comm_grp_cd = 'PLAN_APL_FG_CD' AND cd3.comm_cd = mst.plan_apl_fg_cd AND cd4.comm_grp_cd(+) = 'UPD_STS_FG_CD' AND cd4.comm_cd(+)= mst.upd_sts_fg_cd AND cd5.comm_grp_cd(+) = 'UPD_SCOP_CD' AND cd5.comm_cd(+) = usm.upd_scop_cd AND mst.plan_id = apmap.auth_plan_id(+) AND mst.root_plan_id = apmap.root_plan_id(+) AND apmap.ref_plan_id = apmst.plan_id(+) AND apmst.plan_id = apswmap.plan_id(+) AND apmst.stb_sw_plan_last_ver = apswmap.stb_sw_ver(+) AND apswmap.sw_id = apswmst.sw_id(+) AND apmst.plan_id = apswMapCnt.plan_id(+) AND apcommcd.comm_grp_cd(+) = 'UPD_SCOP_CD' AND apcommcd.comm_cd(+) = apswmst.upd_scop_cd AND mst.plan_apl_fg_cd in ('01','02','03')
AND UPPER(mst.plan_nm) like '%' || UPPER(#{schPlanNm}) || '%'
AND mst.modl_cd IN
#{value}
AND mst.upd_sts_fg_cd = #{schUpdStsFgCd}
AND EXISTS ( SELECT 1 FROM UM_UPD_PLAN_EXE_SCH_LST UUEXE WHERE UUEXE.PLAN_ID = mst.PLAN_ID AND (UUEXE.STM_FIR_REG_USER_ID IN
#{value}
OR UUEXE.STM_LAST_UPD_USER_ID IN
#{value}
) )
AND EXISTS (SELECT 1 FROM UM_UPD_PLAN_CUG_MAP UUPCM WHERE UUPCM.PLAN_ID = mst.PLAN_ID AND UUPCM.CUG_ID IN
#{value}
)
AND EXISTS ( SELECT 1 FROM UM_UPD_PLAN_EXE_SCH_LST UUEXE WHERE UUEXE.PLAN_ID = mst.PLAN_ID AND ((UUEXE.STM_FIR_REG_DATE >= TO_DATE(#{schFromDt}, 'YYYY-MM-DD') OR UUEXE.STM_LAST_UPD_DATE >= TO_DATE(#{schFromDt}, 'YYYY-MM-DD')) AND (UUEXE.STM_FIR_REG_DATE <= TO_DATE(#{schToDt}, 'YYYY-MM-DD') OR UUEXE.STM_LAST_UPD_DATE <= TO_DATE(#{schToDt}, 'YYYY-MM-DD')) ) )
AND EXISTS ( SELECT COUNT(*) FROM UM_UPD_PLAN_ERR_MST UUPEM WHERE UUPEM.PLAN_ID = mst.PLAN_ID GROUP BY UUPEM.PLAN_ID, UUPEM.EXE_SCH_ID, UUPEM.STB_ID, UUPEM.MAC_ADDR HAVING COUNT(*) >= #{schErrCnt} )
ORDER BY mst.stm_last_upd_date DESC

/** selectListExeScheForStatistics005 */ SELECT esch.plan_id ,esch.exe_sch_id ,esch.exe_sch_nm ,esch.exe_sch_expl ,esch.downld_mt_fg_cd ,esch.exe_sch_fr_dy ,esch.exe_sch_to_dy ,esch.cust_noty_mt_lst ,esch.push_delay_tm ,esch.push_limit_cnt ,REGEXP_REPLACE(esch.exe_sch_alrm_dd,',','|') AS exeSchAlrmDD ,esch.exe_sch_alrm_hh AS exeSchAlrmHH ,REGEXP_REPLACE(esch.exe_sch_alrm_mi,',','|') AS exeSchAlrmMI ,'' AS selTgt ,NVL(esch.to_goal_qty,0) AS toGoalQty ,NVL(esch.tgt_qty,0) AS tgtQty ,NVL(esch.conf_qty,0) AS confQty ,NVL(esch.end_cond_rt,0) AS endCondRt ,NVL(esch.wat_qty,0) AS notPrgQty ,NVL(esch.prg_qty,0) AS prgQty ,NVL(esch.err_qty,0) AS errQty ,NVL(esch.to_qty,0) AS endQty ,esch.scr_disp_fg_cd ,esch.slp_wat_tm ,esch.cust_noty_msg ,esch.cust_noty_mt_lst ,esch.scr_disp_tm ,esch.upd_sts_fg_cd ,NVL(esch.stop_yn,'N') AS stopYn ,cd1.cd_nm as updStsFgNm ,(SELECT user_nm FROM ad_user_mst WHERE user_id = esch.STM_FIR_REG_USER_ID) STM_FIR_REG_USER_NM ,TO_CHAR(esch.STM_FIR_REG_DATE,'YYYY.MM.DD HH24:MI') STM_FIR_REG_DATE ,NVL((SELECT user_nm FROM ad_user_mst WHERE user_id = esch.STM_LAST_UPD_USER_ID), esch.STM_LAST_UPD_USER_ID) STM_LAST_UPD_USER_NM ,TO_CHAR(esch.stm_last_upd_date,'YYYY.MM.DD HH24:MI') stm_last_upd_date ,CASE WHEN esch.upd_sts_fg_cd = '1' THEN 'Y' ELSE 'N' END enableUpdate ,CASE WHEN esch.to_goal_qty > 0 THEN 'N' ELSE 'Y' END totTgtYn FROM um_upd_plan_exe_sch_lst esch ,ad_comm_cd cd1 WHERE plan_id = #{planId} AND cd1.comm_grp_cd = 'UPD_STS_FG_CD' AND cd1.comm_cd = esch.upd_sts_fg_cd
AND EXISTS ( SELECT COUNT(*) FROM UM_UPD_PLAN_ERR_MST UUPEM WHERE UUPEM.PLAN_ID = esch.PLAN_ID AND UUPEM.EXE_SCH_ID = esch.EXE_SCH_ID GROUP BY UUPEM.EXE_SCH_ID, UUPEM.STB_ID, UUPEM.MAC_ADDR, UUPEM.ERR_CD HAVING COUNT(*) >= #{schErrCnt} )
AND EXISTS (SELECT 1 FROM UM_UPD_PLAN_EXE_SCH_LST UUEXE WHERE UUEXE.PLAN_ID = esch.PLAN_ID AND UUEXE.EXE_SCH_ID = esch.EXE_SCH_ID AND (UUEXE.STM_FIR_REG_USER_ID IN
#{value}
OR UUEXE.STM_LAST_UPD_USER_ID IN
